// Enhanced Input Processor with refinement support
const item = $input.first();
const data = item.json || {};
const body = data.body || data;
const binary = item.binary || {};

// Extract core data
const sessionId = body.sessionId || body.session_id || `session_${Date.now()}`;
const action = body.action || 'process'; // process, analyze, refine, approve, generate, chat
const message = body.message || body.text || body.chatInput || '';
let extractedText = body.extracted_text || body.extractedText || '';
const feedback = body.feedback || '';
const priorAnalysis = body.analysis || null;

// Check for files
let files = [];
let fileIndex = 0;
const binaryPrefix = 'files';

while (binary[`${binaryPrefix}${fileIndex}`]) {
  const file = binary[`${binaryPrefix}${fileIndex}`];
  files.push({
    filename: file.fileName,
    mimeType: file.mimeType,
    binaryKey: `${binaryPrefix}${fileIndex}`,
    size: file.data ? file.data.length : 0
  });
  fileIndex++;
}

// Convert message to extractedText if no files and no existing extractedText
if (!extractedText && message && files.length === 0) {
  extractedText = message;
}

// Enhanced workflow path determination
let workflowPath = 'unknown';

if (action === 'approve') {
  workflowPath = 'generation';
} else if (action === 'refine' || feedback) {
  workflowPath = 'refine';
} else if (action === 'generate') {
  workflowPath = 'generation';
} else if (files.length > 0 && !extractedText) {
  workflowPath = 'extraction';
} else if (extractedText || message.length > 100) {
  workflowPath = 'analysis';
} else if (message && message.length < 100) {
  workflowPath = 'chat';
} else {
  workflowPath = 'greeting';
}

return {
  json: {
    sessionId: sessionId,
    action: action,
    workflowPath: workflowPath,
    message: message,
    extractedText: extractedText,
    feedback: feedback,
    priorAnalysis: priorAnalysis,
    files: files,
    hasFiles: files.length > 0,
    timestamp: new Date().toISOString()
  },
  binary: binary
};

// Combine all extracted texts and proceed to analysis
const items = $input.all();
const sessionData = items[0].json;
const extractedTexts = items.map(item => {
  if (item.json.choices && item.json.choices[0]) {
    return item.json.choices[0].message.content;
  }
  return '';
}).filter(text => text.length > 0);

const combinedText = extractedTexts.join('\n\n---DOCUMENT SEPARATOR---\n\n');

return {
  json: {
    sessionId: sessionData.sessionId,
    extractedText: combinedText,
    workflowPath: 'analysis', // Force to analysis after extraction
    message: 'Analyze this extracted HVAC content',
    fileCount: sessionData.files?.length || 0,
    totalCharacters: combinedText.length,
    timestamp: new Date().toISOString()
  }
};

parameters.text:
You are an expert HVAC controls engineer. Analyze or refine HVAC sequences based on inputs.

**Available Inputs:**
- Extracted Text: {{ $json.extractedText || 'None' }}
- User Message: {{ $json.message || 'None' }}
- Prior Analysis: {{ JSON.stringify($json.priorAnalysis || {}) }}
- User Feedback: {{ $json.feedback || 'None' }}

**Your Task:**
If this is initial analysis, extract I/O points and create control logic from the text.
If this is refinement (prior analysis + feedback provided), improve the analysis based on feedback.

**Required Output Structure:**
```json
{
  "io_points": {
    "inputs": ["list of sensor/input points"],
    "outputs": ["list of actuator/output points"]
  },
  "control_blocks": ["list of logical control blocks"],
  "pseudocode": [
    {
      "block": "Block Name",
      "logic": ["array of logic steps"]
    }
  ],
  "issues": ["any ambiguities or missing info"]
}
```

Provide detailed, accurate analysis suitable for building automation. Use the `format_final_json_response` tool to return the final JSON output.

