// Format BOG generation request from approved analysis
const data = $input.first().json;
let analysis;

// Handle different data sources
if (data.data && typeof data.data === 'string') {
  try {
    analysis = JSON.parse(data.data);
  } catch (e) {
    analysis = data;
  }
} else {
  analysis = data.data || data;
}

// Ensure we have the analysis structure
if (!analysis.io_points) {
  throw new Error('No analysis data found for BOG generation');
}

const bogRequest = {
  bog_name: `hvac_control_${data.session_id || Date.now()}`,
  session_id: data.session_id,
  inputs: (analysis.io_points?.inputs || []).map(input => ({
    name: input.replace(/\s+/g, '_').toLowerCase(),
    type: 'sensor',
    units: 'units',
    default_value: 0.0
  })),
  outputs: (analysis.io_points?.outputs || []).map(output => ({
    name: output.replace(/\s+/g, '_').toLowerCase(),
    type: 'actuator',
    control_type: 'modulating',
    range: '0-100%',
    default_value: 0.0
  })),
  control_sequences: (analysis.pseudocode || []).map((item, idx) => ({
    name: item.block || `Sequence_${idx + 1}`,
    type: 'sequence',
    description: `Control logic for ${item.block}`,
    logic: Array.isArray(item.logic) ? item.logic.join('\n') : item.logic
  })),
  metadata: {
    generated_at: new Date().toISOString(),
    workflow_version: 'iterative-1.0',
    session_id: data.session_id
  }
};

return { json: bogRequest };

// Format responses with proper pause-and-approve flow
const data = $input.first().json;
const workflowPath = data.workflowPath || 'unknown';
let response = {};

switch(workflowPath) {
  case 'extraction':
    response = {
      status: 'extraction_complete',
      sessionId: data.sessionId,
      message: 'Document text extracted successfully. Analyzing HVAC content...',
      extractedText: data.extractedText,
      characterCount: data.totalCharacters,
      nextStep: 'analysis'
    };
    break;

  case 'analysis':
  case 'refine':
    response = {
      status: 'ready_for_review',
      sessionId: data.sessionId,
      message: workflowPath === 'refine' ? 
        'Analysis refined based on your feedback. Please review:' : 
        'HVAC analysis complete! Please review the extracted components:',
      analysis: {
        inputs: data.io_points?.inputs || [],
        outputs: data.io_points?.outputs || [],
        controlBlocks: data.control_blocks || [],
        pseudocode: data.pseudocode || [],
        issues: data.issues || []
      },
      actions: {
        approve: {
          label: '✅ Approve & Generate BOG',
          action: 'approve',
          description: 'Proceed with BOG file generation'
        },
        refine: {
          label: '🔄 Request Changes',
          action: 'refine',
          description: 'Provide feedback to improve the analysis'
        }
      },
      readyForBOG: true
    };
    break;

  case 'generation':
    response = {
      status: 'generation_complete',
      sessionId: data.sessionId,
      message: 'BOG file generated successfully!',
      downloadUrl: data.download_url || data.downloadUrl,
      bogFilePath: data.bog_file_path || data.bogFilePath,
      components: data.components || {
        inputs: data.inputs?.length || 0,
        outputs: data.outputs?.length || 0,
        control_sequences: data.control_sequences?.length || 0
      }
    };
    break;

  case 'chat':
    response = {
      status: 'chat_response',
      sessionId: data.sessionId,
      message: data.choices?.[0]?.message?.content || 'I can help you with HVAC control sequences and BOG generation.',
      requiresAction: false
    };
    break;

  default:
    response = {
      status: 'ready',
      sessionId: data.sessionId,
      message: 'Welcome to PyBOG Control Builder! Upload a PDF or describe your HVAC control sequence.',
      capabilities: [
        'Extract text from PDF documents',
        'Analyze HVAC control sequences',
        'Iterative design with feedback',
        'Generate BOG files'
      ]
    };
}

response.timestamp = new Date().toISOString();
return { json: response };

