// Fan-out: produce one item per uploaded file
const item = $input.first();
const files = (item.json?.files || []);
const out = [];

if (files.length) {
  for (const f of files) {
    const key = f.binaryKey;
    if (key && item.binary?.[key]) {
      out.push({
        json: { ...item.json, binaryKey: key, fileName: f.filename, mimeType: f.mimeType },
        binary: { [key]: item.binary[key] }
      });
    }
  }
} else if (item.binary && Object.keys(item.binary).length) {
  // Fallback if files[] is missing: split all binary keys found
  for (const key of Object.keys(item.binary)) {
    out.push({
      json: { ...item.json, binaryKey: key },
      binary: { [key]: item.binary[key] }
    });
  }
} else {
  // If there are no files, just pass original through
  out.push(item);
}

return out;

